from pyspark.sql.functions import udf
from pyspark.sql.types import StringType

# Python UDF — serialises every row across the JVM↔Python boundary (slow)
@udf(returnType=StringType())
def classify_salary(salary):
    if salary is None:
        return "unknown"
    elif salary < 50_000:
        return "low"
    elif salary < 100_000:
        return "medium"
    else:
        return "high"

df = df.withColumn("salary_band", classify_salary(F.col("salary")))

from pyspark.sql.functions import pandas_udf
from pyspark.sql.types import StringType
import pandas as pd

# Pandas UDF — operates on batches as Pandas Series; much faster than row-by-row UDFs
@pandas_udf(StringType())
def classify_salary_vectorised(salary_series: pd.Series) -> pd.Series:
    return pd.cut(
        salary_series,
        bins=[-float("inf"), 50_000, 100_000, float("inf")],
        labels=["low", "medium", "high"]
    ).astype(str)

df = df.withColumn("salary_band", classify_salary_vectorised(F.col("salary")))

# Broadcast a Python dict to all executors — avoid re-serialising per task
country_map = {"US": "United States", "GB": "United Kingdom", "DE": "Germany"}
bc_country = spark.sparkContext.broadcast(country_map)

# Use inside a UDF
@udf(returnType=StringType())
def expand_country(code):
    return bc_country.value.get(code, "Unknown")

df = df.withColumn("country_name", expand_country(F.col("country_code")))
